fixes.origin:
location = content_root / slug
with open(location, "r", encoding="utf-8") as reader:
    return reader.read()

fixes.replacement:
base = content_root.resolve()
location = (content_root / slug).resolve()
if base not in location.parents and location != base:
    abort(400)
with open(location, "r", encoding="utf-8") as reader:
    return reader.read()
